function loadInfo(){$.get("https://blockchain.info/q/getreceivedbyaddress/"+address,function(n){window.total=parseInt(n),setTotal(n)})}function value(n){return _.sum(_.map(n.x.out,function(n){return n.addr==address?n.value:0}))}function setTotal(n){$(".amount-btc").text((n/1e8).toFixed(2)),$.get("https://blockchain.info/q/24hrprice",function(t){$(".amount-usd").text(accounting.formatMoney(n*t/1e8))})}function dance(){window.dancing=!0,$.get(giphyEnpoint+"?api_key="+giphyApiKey+"&tag="+giphyTag,function(n){$(".address-container").append('<img class=giphy style="display: none" src='+n.data.image_url+"></img>")}),$(".address").fadeOut(2e3,function(){window.dancing=!0,$(".giphy").fadeIn(2e3);var n=new Audio("sounds/sandstorm.ogg");n.play(),n.ontimeupdate=function(){n.currentTime>27&&$(".giphy").fadeOut(2e3,function(){$(".address").fadeIn(2e3,function(){window.dancing=!1})})}})}var address="14xEPWuHC3ybPMfv8iTZZ29UCLTUSoJ8HL",socket=new WebSocket("wss://ws.blockchain.info/inv"),giphyApiKey="dc6zaTOxFJmzC",giphyEnpoint="http://api.giphy.com/v1/gifs/random",giphyTag="dance";window.dancing=!1,window.total=0,$(function(){socket.onopen=function(){socket.send(JSON.stringify({op:"addr_sub",addr:address}))},socket.onmessage=function(n){var t=JSON.parse(n.data);window.total=window.total+value(t),setTotal(window.total),window.dancing||dance()},loadInfo()});